- **input**：定义数据来源（file/kafka/beats/tcp/http 等）
- **filter**：数据清洗、解析、转换（grok 正则、json 解析、geoip、mutate 字段操作）
- **output**：定义输出目标（elasticsearch/kafka/stdout 等）

```sh
# 1. 输入模块：从Kafka拉取日志（与Kafka主题对应）
input {
  kafka {
    bootstrap_servers => "192.168.1.200:9092,192.168.1.201:9092,192.168.1.202:9092"
    topics => ["nginx-log-topic"]  # 对应Kafka主题
    group_id => "logstash-nginx-group"  # 消费组ID，避免重复消费
    codec => "plain"  # 日志为自定义文本格式，非JSON，用plain解析
  }
}

# 2. 过滤模块：核心清洗转换（解析自定义格式、结构化、去冗余）
filter {
  # 核心：用grok解析自定义Nginx日志（匹配你提供的log_format main格式）
  grok {
    match => { 
      "message" => '%{DATA:http_x_real_ip} \| %{IPORHOST:remote_addr} \| %{DATA:remote_user} \| \[%{DATE_EPOCH:time_iso8601:date}\] \| "%{DATA:request}" \| %{NUMBER:status:int} \| %{NUMBER:body_bytes_sent:int} \| %{NUMBER:request_time:float} \| %{DATA:upstream_addr} \| %{DATA:upstream_status} \| %{NUMBER:upstream_response_time:float} \| "%{DATA:http_referer}" \| "%{DATA:http_user_agent}" \| "%{DATA:http_x_forwarded_for}"'
    }
    tag_on_failure => ["_grokparsefailure"]  # 解析失败的日志标记，便于排查
  }

  # 时间格式化（time_iso8601已为标准格式，直接赋值给@timestamp）
  date {
    match => { "time_iso8601" => ["yyyy-MM-dd'T'HH:mm:ssZ"] }
    target => "@timestamp"  # 赋值给Logstash默认时间字段，便于后续检索
    remove_field => "time_iso8601"  # 移除原始时间字段，避免冗余
  }

  # 字段处理（去冗余、补充字段）
  mutate {
    # 处理空值（将"-"替换为null，更规范）
    gsub => [ "http_x_real_ip", "^-$", "" ]
    gsub => [ "remote_user", "^-$", "" ]
    # 移除无用字段
    remove_field => ["message", "@version"]
    # 补充日志来源字段，便于分类管理
    add_field => { "log_source" => "nginx" }
  }

  # 过滤无效日志（如404状态码的/favicon.ico请求，根据需求调整）
  if [status] == 404 and [request] =~ /favicon.ico/ {
    drop {}  # 丢弃该类无用日志，减少存储压力
  }
}

# 3. 输出模块：输出至ElasticSearch（结构化日志存储）
output {
  elasticsearch {
    hosts => ["http://192.168.1.210:9200", "http://192.168.1.211:9200"]  # ES集群地址
    index => "nginx-log-%{+YYYY.MM.dd}"  # 按天生成ES索引，便于管理
    document_type => "_doc"
  }

  # 输出至控制台（测试用，生产可注释，查看转换后的结构化日志）
  stdout { codec => rubydebug }
}
```

**负载均衡策略**:

| 算法                    | 原理                       | 适用场景                       |
| ----------------------- | -------------------------- | ------------------------------ |
| 轮询（Round Robin）     | 依次分配请求               | 后端性能相同的无状态服务       |
| 加权轮询（Weighted RR） | 按权重比例分配             | 后端性能不同时                 |
| 最少连接（Least Conn）  | 分配给当前连接数最少的节点 | 请求处理时间差异大             |
| IP Hash                 | 同一 IP 固定分配到同一节点 | 需要会话保持（Session Sticky） |

+ **轮询** (round-robin) - 默认,请求依次分发
+ **权重** (weight) - 按权重分配，高性能机器权重拉高，差异化承载
+ **IP Hash** - 同一 IP 始终访问同一后端，解决会话保持
+ **最少连接** (least_conn) - 优先分配给连接数少的服务器，适合后端处理耗时不均场景；

```nginx
upstream backend {
    # 轮询（默认）
    server 192.168.1.10:8080;
    server 192.168.1.11:8080;
    # 权重
    # server 192.168.1.10:8080 weight=3;
    # server 192.168.1.11:8080 weight=1;

    # IP Hash（会话保持）
    # ip_hash;

    # 最少连接
    # least_conn;
}
server {
    listen 80;
    location / {
        proxy_pass http://backend;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}
```

