+ Nginx 本身性能优化，适配 CPU、开启零拷贝和事件驱动，提升并发能力

```sh
# 1.进程与CPU优化
worker_processes auto;
worker_cpu_affinity auto;
worker_rlimit_nofile 655350;
# 2.事件模型
events {
    use epoll;  # Linux高性能事件模型
    worker_connections 65535;
    multi_accept on;  # 一次接受多个新连接
}
# 3.基础全局参数
http {
    # 隐藏版本号
    server_tokens off;

    # 零拷贝、网络优化
    sendfile on;
    tcp_nopush on;
    tcp_nodelay on;

    # 超时优化（防僵死连接）
    keepalive_timeout 65;
    client_header_timeout 10s;
    client_body_timeout 10s;
    send_timeout 15s;
}
```

+ 反向代理优化，透传真实 IP、配置后端长连接，减少后端压力

```sh
# 1.完整透传真实IP与协议
proxy_set_header Host $host;
proxy_set_header X-Real-IP $remote_addr;
proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
proxy_set_header X-Forwarded-Proto $scheme;
proxy_set_header Connection "";

# 2.超时优化（防止504/502）
proxy_connect_timeout 5s;
proxy_read_timeout 30s;
proxy_send_timeout 15s;

# 3.后端长连接优化（解决端口耗尽、频繁握手）
upstream backend_api {
    server 10.0.0.10:8080;
    server 10.0.0.11:8080;
    keepalive 100;  # 长连接池
}
# 启用HTTP1.1长连接
proxy_http_version 1.1;
```

+ 静态资源优化，开启 Gzip 和浏览器缓存，做动静分离

```sh
 gzip on;
 gzip_comp_level 5;  # 压缩级别，默认是6，可以设置为1-9之间的任意整数
 gzip_min_length 1024;  # 1KB以上才压缩
 gzip_proxied any;  # 适用于所有类型的连接，包括后端连接
 gzip_vary on;  # 根据Accept-Encoding头部增加Vary头部，防止代理服务器缓存的干扰
gzip_types text/plain text/css application/javascript application/xml application/json image/svg+xml application/x-font-ttf application/x-font-opentype application/vnd.ms-fontobject application/octet-stream;
```

